func personaToGQL(p *persona.Persona) *Persona {
	source := p.Source
	if source == "" {
		source = persona.SourceLibrary
	}
	var filePath *string
	if p.FilePath != "" {
		fp := p.FilePath
		filePath = &fp
	}
	return &Persona{
		ID:          "persona-" + p.Name,
		Name:        p.Name,
		Roles:       p.Roles,
		Description: p.Description,
		Tags:        p.Tags,
		Content:     p.Content,
		Body:        p.Content,
		Source:      source,
		Bindings:    []*PersonaBinding{},
		FilePath:    filePath,
	}
}

